using UnityEngine;public class Controller : MonoBehaviour{    private const float ArrowOffset = 0.8f;    private const string HorizontalAxis = "Horizontal";    private const string VerticalAxis = "Vertical";    [SerializeField] private Rigidbody _rigidbody;    [SerializeField] private Transform _arrow;    [SerializeField] private float _jumpForce = 500f;    [SerializeField] private float _speed = 30f;    private bool _isJumpPressed;    private float _horizontalInput;    private void Update()    {        if (Input.GetKeyDown(KeyCode.Space))        {            _isJumpPressed = true;        }        float verticalInput = Input.GetAxisRaw(VerticalAxis);        float horizontalInput = Input.GetAxisRaw(HorizontalAxis);        Vector3 direction = new(horizontalInput, 0, verticalInput);        Vector3 normalizedDirection = direction.normalized;        _rigidbody.AddForce(normalizedDirection * (_speed * Time.deltaTime), ForceMode.Force);    }    private void FixedUpdate()    {        if (_isJumpPressed)        {            _rigidbody.AddForce(Vector3.up * _jumpForce, ForceMode.Force);            _isJumpPressed = false;        }    }    public void Stop()    {        _rigidbody.velocity = Vector3.zero;        _rigidbody.angularVelocity = Vector3.zero;    }}